document.addEventListener("DOMContentLoaded", function () { const body = document.body; const readingBar = document.querySelector("[data-reading-bar]"); if (!readingBar || !body.classList.contains("single-post")) { return; } const readingArticle = document.querySelector("[data-reading-article]"); const readingProgress = readingBar.querySelector("[data-reading-progress]"); let lastY = window.scrollY || 0; let ticking = false; const threshold = 140; function updateReadingBar() { const currentY = window.scrollY || 0; const scrollingDown = currentY > lastY + 4; const scrollingUp = currentY < lastY - 4; if (currentY <= threshold) { body.classList.remove("is-reading-down"); } else if (scrollingDown) { body.classList.add("is-reading-down"); } else if (scrollingUp) { body.classList.remove("is-reading-down"); } if (readingArticle && readingProgress) { const articleTop = readingArticle.offsetTop; const articleHeight = readingArticle.offsetHeight; const viewportHeight = window.innerHeight || document.documentElement.clientHeight || 1; const progressStart = articleTop; const progressDistance = Math.max(articleHeight - viewportHeight, 1); const rawProgress = ((currentY - progressStart) / progressDistance) * 100; const clampedProgress = Math.max(0, Math.min(100, rawProgress)); readingProgress.style.width = clampedProgress + "%"; } lastY = currentY; ticking = false; } window.addEventListener( "scroll", function () { if (!ticking) { window.requestAnimationFrame(updateReadingBar); ticking = true; } }, { passive: true } ); updateReadingBar(); });
